// --- Project Autogenerated Route Config Tests ---

func TestUpdateAutogeneratedRouteConfigOnProject(t *testing.T) {
	server := mockGraphQLServer(t, func(query string, variables map[string]any) (any, error) {
		if !strings.Contains(query, "updateAutogeneratedRouteConfigOnProject") {
			t.Errorf("expected updateAutogeneratedRouteConfigOnProject mutation")
		}
		enabled := true
		allowPR := true
		tlsAcme := true
		return map[string]any{
			"updateAutogeneratedRouteConfigOnProject": map[string]any{
				"enabled":          &enabled,
				"allowPullRequests": &allowPR,
				"prefixes":         []string{"www", "staging"},
				"tlsAcme":          &tlsAcme,
			},
		}, nil
	})
	defer server.Close()

	c := NewClient(server.URL, "token")
	cfg, err := c.UpdateAutogeneratedRouteConfigOnProject(context.Background(), "my-project", map[string]any{
		"enabled": true,
	})
	if err != nil {
		t.Fatalf("UpdateAutogeneratedRouteConfigOnProject failed: %v", err)
	}
	if cfg.Enabled == nil || !*cfg.Enabled {
		t.Error("expected enabled=true")
	}
	if len(cfg.Prefixes) != 2 {
		t.Errorf("expected 2 prefixes, got %d", len(cfg.Prefixes))
	}
}

