// --- Environment Autogenerated Route Config Tests ---

func TestUpdateAutogeneratedRouteConfigOnEnvironment(t *testing.T) {
	server := mockGraphQLServer(t, func(query string, variables map[string]any) (any, error) {
		if !strings.Contains(query, "updateAutogeneratedRouteConfigOnEnvironment") {
			t.Errorf("expected updateAutogeneratedRouteConfigOnEnvironment mutation")
		}
		enabled := false
		return map[string]any{
			"updateAutogeneratedRouteConfigOnEnvironment": map[string]any{
				"enabled": &enabled,
			},
		}, nil
	})
	defer server.Close()

	c := NewClient(server.URL, "token")
	cfg, err := c.UpdateAutogeneratedRouteConfigOnEnvironment(context.Background(), "my-project", "main", map[string]any{
		"enabled": false,
	})
	if err != nil {
		t.Fatalf("UpdateAutogeneratedRouteConfigOnEnvironment failed: %v", err)
	}
	if cfg.Enabled == nil || *cfg.Enabled {
		t.Error("expected enabled=false")
	}
}

func TestGetAutogeneratedRouteConfigForEnvironment(t *testing.T) {
	callCount := 0
	server := mockGraphQLServer(t, func(query string, variables map[string]any) (any, error) {
		callCount++
		if callCount == 1 {
			// First call: GetProjectByName
			if !strings.Contains(query, "projectByName") || strings.Contains(query, "autogeneratedRouteConfig") {
				t.Errorf("expected projectByName query (without autogeneratedRouteConfig)")
			}
			return map[string]any{
				"projectByName": map[string]any{
					"id":   42,
					"name": "my-project",
				},
			}, nil
		}
		// Second call: environmentByName
		if !strings.Contains(query, "environmentByName") {
			t.Errorf("expected environmentByName query")
		}
		enabled := true
		return map[string]any{
			"environmentByName": map[string]any{
				"autogeneratedRouteConfig": map[string]any{
					"enabled": &enabled,
				},
			},
		}, nil
	})
	defer server.Close()

	c := NewClient(server.URL, "token")
	cfg, err := c.GetAutogeneratedRouteConfigForEnvironment(context.Background(), "my-project", "main")
	if err != nil {
		t.Fatalf("GetAutogeneratedRouteConfigForEnvironment failed: %v", err)
	}
	if cfg.Enabled == nil || !*cfg.Enabled {
		t.Error("expected enabled=true")
	}
	if callCount != 2 {
		t.Errorf("expected 2 calls (GetProjectByName + environmentByName), got %d", callCount)
	}
}

